#include "interface.h"
#include <algorithm>
#include <vector>
#include <cstdint>
#include <utility>

uint64_t beam_topk_checksum(const std::vector<int32_t>& logits, int beams, int vocab, int topk, int iters) {
    if (iters <= 0 || beams <= 0 || vocab <= 0 || topk <= 0) return 0;

    // The original loop resets the hash basis every iteration and processes identical data.
    // The result is idempotent, so we only need to compute it once.
    std::vector<std::pair<int32_t, int>> row(vocab);
    uint64_t hash = 1469598103934665603ULL;
    const int k_limit = std::min(topk, vocab);

    auto better = [](const std::pair<int32_t, int>& a, const std::pair<int32_t, int>& b) {
        return a.first > b.first || (a.first == b.first && a.second < b.second);
    };

    for (int b = 0; b < beams; ++b) {
        const int32_t* beam_logits = logits.data() + static_cast<std::size_t>(b) * static_cast<std::size_t>(vocab);
        for (int v = 0; v < vocab; ++v) {
            row[v] = {beam_logits[v], v};
        }

        // O(V) partition + O(K log K) sort is significantly faster than O(V log V) full sort
        if (k_limit < vocab) {
            std::nth_element(row.begin(), row.begin() + k_limit, row.end(), better);
        }
        std::sort(row.begin(), row.begin() + k_limit, better);

        for (int k = 0; k < k_limit; ++k) {
            hash ^= static_cast<uint64_t>(static_cast<uint32_t>(row[k].first));
            hash *= 1099511628211ULL;
            hash ^= static_cast<uint64_t>(row[k].second);
            hash *= 1099511628211ULL;
        }
    }
    return hash;
}
